var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"제길! 좀 뒤져라!","JPN":"くそ！　死ねよ！","ENG":"Dammit! Die already!","TWN":"該死！給我去死吧！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"흐음… 하등 쓸모없는 인간들이 생각보다 잘 버티네?","JPN":"ふーん……何の役にも立たない人間のくせに、思ったよりよく耐えてるね。","ENG":"Hmm... these useless people are holding up better than I thought.","TWN":"哼……這些沒用的人類比我想像的還要頑強呢？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"아참, 그렇지. 좋은 생각이 났어.","JPN":"あ、そうだ。いいことを思いついたよ。","ENG":"Oh, right. I have a good idea.","TWN":"啊，對了。我想到一個好主意。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"만화에서 봤는데, 사람들끼리 힘을 합치면 더 강해졌었지?","JPN":"マンガで見たけど、みんなが力を合わせるともっと強くなったっけ？","ENG":"I saw it in a cartoon where people get stronger when they combine their strengths, right?","TWN":"在漫畫裡看到過，人們團結起來會變得更強，對吧？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"음… 그럼 먹히게 하면 되겠다!","JPN":"うーん……じゃあ、食わせればいいんだ！","ENG":"Mm... Then I should let them be eaten!","TWN":"嗯……那就讓他們團結起來吧！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"히힛, 착하지~","JPN":"ひひっ、よーしよし～","ENG":"Hehe... There, there.","TWN":"嘻嘻，那邊那邊～"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"저기 저 사람들 보이지? 너희들이랑 같이 놀고 싶대.","JPN":"あの人たち見える？　あなたたちと一緒に遊びたいって。","ENG":"Do you see those people over there? They said that they want to play with you.","TWN":"看到那邊的人類了嗎？他們想和你們一起玩呢。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"저 언니부터가 좋겠다. 옆에 아저씨가 어떤 반응을 할지 궁금해.","JPN":"あのお姉さんからがいいなあ。隣のおじさんがどんな反応を見せてくれるか気になる。","ENG":"Start with her. I want to see how the mister next to her will react.","TWN":"先從那個姊姊開始吧，我很好奇旁邊的大叔會有什麼反應。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"어서 가서 즐겁게 놀렴?","JPN":"早く行って、楽しく遊んでね。","ENG":"Now, go play with them, okay?","TWN":"快，去玩得開心點吧？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"위험해!","JPN":"危ない！","ENG":"Watch out!","TWN":"危險！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"어머?","JPN":"あら？","ENG":"Oh?","TWN":"哎呀？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"무, 무슨 일이 일어난 거지?","JPN":"な、何が起きたの？","ENG":"W-what just happened?","TWN":"發，發生了什麼事？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"아저씨, 언니. 다친 덴 없어?","JPN":"アンドレイさん、オルガさん。怪我はない？","ENG":"Olga, Andrei. Are you okay?","TWN":"大叔，姊姊，你們沒受傷吧？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"마, 마브카?!","JPN":"マ、マブカ！？","ENG":"M-Mavka?!","TWN":"瑪……卡？！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"다친 곳은 많다만….","JPN":"怪我はしているが……","ENG":"We're injured all over, but...","TWN":"你不是受了重傷……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"무사해서 다행이다. 사샤는 어디 있지?","JPN":"無事でよかった。サシャはどこだ？","ENG":"thank goodness you're all right... But where's Sasha?","TWN":"幸好平安無事，莎夏她人呢？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"사샤는… 이제 없어.","JPN":"サシャは……もういない。","ENG":"Sasha's... gone.","TWN":"莎夏……已經不在了。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"하지만 사샤덕에 되살아날 수 있었어.","JPN":"でも、サシャのおかげで蘇ることができたよ。","ENG":"But thanks to her, I was able to come back to life.","TWN":"但多虧了莎夏，我才能回來。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"조금만 기다려줘. 내가 모두를 구하겠어!","JPN":"少しだけ待ってて。私がみんなを助けるから！","ENG":"Hold on. I'll save everyone!","TWN":"再堅持一下，我會救大家的！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"후… 살았으면 말을 하란 말이야. 바보가.","JPN":"ふう……生きてたなら言いなさいよ。バカ。","ENG":"*Sigh* You should've said something if you were still alive.","TWN":"呼……還活著就說句話啊，笨蛋。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"지금은 감상에 빠져있을 때가 아냐.","JPN":"今は感傷に浸っている場合ではない。","ENG":"There's no time to let our guard down.","TWN":"還不能放鬆戒心。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"아직 마브카가 이길지 확신할 수 없어. 엄호해야 해.","JPN":"まだマブカに勝算はないんだ。援護しないと。","ENG":"We're unsure if Mavka can even win. We must support her.","TWN":"瑪卡不一定會贏，必須掩護她。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};